const body = $input.item.json.body;

if (!body || !body.products || !Array.isArray(body.products)) {
  throw new Error('❌ Formato inválido');
}

if (body.products.length === 0) {
  throw new Error('❌ Nenhum produto');
}

if (!body.integrations || !Array.isArray(body.integrations)) {
  throw new Error('❌ Nenhuma integração');
}

return { json: body };

const data = $input.item.json;
const products = data.products;
const integrations = data.integrations;

const envios = [];

products.forEach(product => {
  integrations.forEach(integration => {
    envios.push({
      ...product,
      integrationId: integration.id,
      integrationName: integration.name,
      integrationToken: integration.token,
      chatId: data.chatId
    });
  });
});

return envios.map(e => ({ json: e }));

const p = $json;

if (!p.variacoes || !Array.isArray(p.variacoes) || p.variacoes.length === 0) {
  throw new Error('❌ Sem variações');
}

const tiposVariacao = new Set();
p.variacoes.forEach(v => {
  const variacaoNome = v.variacao?.nome || '';
  if (variacaoNome) {
    variacaoNome.split(';').forEach(part => {
      const [tipo] = part.split(':');
      if (tipo) tiposVariacao.add(tipo.trim());
    });
  }
});

const primeiroTipo = Array.from(tiposVariacao)[0] || 'Tamanho';

const variacoesArray = p.variacoes.map(v => ({
  nome: p.nome,
  codigo: v.codigo,
  preco: parseFloat(v.preco) || 0,
  tipo: "P",
  situacao: "A",
  formato: "S",
  unidade: v.unidade || "UN",
  pesoLiquido: parseFloat(v.pesoLiquido) || 0,
  pesoBruto: parseFloat(v.pesoBruto) || 0,
  volumes: parseInt(v.volumes) || 1,
  itensPorCaixa: parseInt(v.itensPorCaixa) || 1,
  gtin: v.gtin || '',
  gtinEmbalagem: v.gtinEmbalagem || '',
  marca: p.marca || '',
  descricaoCurta: p.descricaoCurta || '',
  descricaoComplementar: p.descricaoComplementar || '',
  categoria: p.categoria || {},
  tributacao: p.tributacao || {},
  dimensoes: v.dimensoes || {},
  variacao: {
    nome: v.variacao?.nome || '',
    produtoPai: { cloneInfo: false }
  }
}));

const productBody = {
  nome: p.nome,
  codigo: p.codigo,
  preco: 0,
  tipo: "P",
  situacao: "A",
  formato: "V",
  unidade: p.unidade || "UN",
  marca: p.marca || '',
  descricaoCurta: p.descricaoCurta || '',
  descricaoComplementar: p.descricaoComplementar || '',
  categoria: p.categoria || {},
  tributacao: p.tributacao || {},
  dimensoes: p.dimensoes || {},
  variacao: { nome: primeiroTipo },
  variacoes: variacoesArray
};

return {
  productBody,
  productCode: p.codigo,
  productName: p.nome,
  integrationId: p.integrationId,
  integrationName: p.integrationName,
  integrationToken: p.integrationToken
};

const blingResponse = $input.item.json;
const metadata = $('Guardar Metadados').item.json;

const result = {
  productCode: metadata.productCode,
  productName: metadata.productName,
  integrationName: metadata.integrationName,
  blingResponse: blingResponse,
  status: (blingResponse.data && blingResponse.data.id) ? 'success' : 'error',
  blingId: blingResponse.data?.id || null,
  warnings: blingResponse.data?.warnings || [],
  timestamp: new Date().toISOString()
};

return { json: result };

const allData = $input.all().map(item => item.json);

const resumo = {
  total: allData.length,
  sucessos: allData.filter(r => r.status === 'success').length,
  erros: allData.filter(r => r.status === 'error').length,
  totalIntegracoes: new Set(allData.map(r => r.integrationName)).size,
  taxaSucesso: '0%'
};

resumo.taxaSucesso = `${((resumo.sucessos / resumo.total) * 100).toFixed(1)}%`;

const detalhes = {
  sucessos: allData.filter(r => r.status === 'success').map(r => ({
    nome: r.productName,
    codigo: r.productCode,
    integracao: r.integrationName,
    blingId: r.blingResponse?.data?.id,
    warnings: r.warnings
  })),
  erros: allData.filter(r => r.status === 'error').map(r => ({
    nome: r.productName,
    codigo: r.productCode,
    integracao: r.integrationName,
    mensagem: r.blingResponse?.error?.message || 'Erro desconhecido'
  }))
};

return { json: { resumo, detalhes } };
